 1→import { DecoratorNode } from "lexical";
 2→import MentionComponent from "./MentionComponent";
 3→
 4→export default class MentionNode extends DecoratorNode {
 5→    static getType() {
 6→        return "mention";
 7→    }
 8→
 9→    static clone(node) {
10→        return new MentionNode(
11→            node.__mentionName,
12→            node.__mentionUserId,
13→            node.__mentionUsername,
14→            node.__key
15→        );
16→    }
17→
18→    constructor(mentionName, mentionUserId, mentionUsername, key) {
19→        super(key);
20→        this.__mentionName = mentionName;
21→        this.__mentionUserId = mentionUserId;
22→        this.__mentionUsername = mentionUsername;
23→    }
24→
25→    isInline() {
26→        return true;
27→    }
28→
29→    createDOM() {
30→        const span = document.createElement("span");
31→        span.className = "mention-node";
32→        return span;
33→    }
34→
35→    updateDOM() {
36→        return false;
37→    }
38→
39→    exportJSON() {
40→        return {
41→            type: "mention",
42→            version: 1,
43→            mentionName: this.__mentionName,
44→            mentionUserId: this.__mentionUserId,
45→            mentionUsername: this.__mentionUsername,
46→        };
47→    }
48→
49→    static importJSON(serializedNode) {
50→        const { mentionName, mentionUserId, mentionUsername } = serializedNode;
51→        return $createMentionNode(mentionName, mentionUserId, mentionUsername);
52→    }
53→
54→    getTextContent() {
55→        return `@${this.__mentionUsername || this.__mentionName}`;
56→    }
57→
58→    decorate(editor) {
59→        const isEditable = editor.isEditable();
60→        return (
61→            <MentionComponent
62→                mentionName={this.__mentionName}
63→                mentionUserId={this.__mentionUserId}
64→                mentionUsername={this.__mentionUsername}
65→                isEditable={isEditable}
66→            />
67→        );
68→    }
69→}
70→
71→export function $createMentionNode(mentionName, mentionUserId, mentionUsername) {
72→    return new MentionNode(mentionName, mentionUserId, mentionUsername);
73→}
74→
75→export function $isMentionNode(node) {
76→    return node instanceof MentionNode;
77→}
