 5→export default function MentionComponent({ mentionName, mentionUserId, mentionUsername, isEditable }) {
 6→    const navigate = useNavigate();
 7→    const { user } = useAuth();
 8→
 9→    const handleClick = (e) => {
10→        if (isEditable) return;
11→        e.stopPropagation();
12→        handleClickProfile(navigate)(e, user?.id, mentionUserId, mentionUsername);
13→    };
14→
15→    return (
16→        <span
17→            className={`mention-chip${isEditable ? ' mention-chip--editing' : ''}`}
18→            onClick={handleClick}
19→            role={isEditable ? undefined : "link"}
20→            tabIndex={isEditable ? undefined : 0}
21→        >
22→            @{mentionName}
23→        </span>
24→    );
25→}
