123→export const getMyLibraryService = async (userId, limit, before) => {
124→    if (!userId) {
125→        throw { status: 400, error: 'userId is required' };
126→    }
127→
128→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 5, 1), 20);
129→
130→    // Get library entries ordered by most recently added
131→    let libQuery = supabase
132→        .from('story_library')
133→        .select('story_id, added_at')
134→        .eq('user_id', userId)
135→        .order('added_at', { ascending: false })
136→        .limit(parsedLimit + 1);
137→
138→    if (before) {
139→        libQuery = libQuery.lt('added_at', before);
140→    }
141→
142→    const { data: libraryEntries, error: libError } = await libQuery;
143→
144→    if (libError) {
145→        console.error('supabase error fetching library:', libError.message);
146→        throw { status: 500, error: 'failed to fetch library' };
147→    }
148→
149→    if (!libraryEntries || libraryEntries.length === 0) {
150→        return { data: [], hasMore: false };
151→    }
152→
153→    const hasMore = libraryEntries.length > parsedLimit;
154→    const slicedEntries = hasMore ? libraryEntries.slice(0, parsedLimit) : libraryEntries;
155→    const storyIds = slicedEntries.map(e => e.story_id);
156→
157→    // Build added_at map for cursor
158→    const addedAtMap = {};
159→    slicedEntries.forEach(e => { addedAtMap[e.story_id] = e.added_at; });
160→
161→    // Batch-fetch stories
162→    const { data: stories, error: storyError } = await supabase
163→        .from('stories')
164→        .select(STORY_SELECT_COLUMNS)
165→        .in('id', storyIds);
166→
167→    if (storyError) {
168→        console.error('supabase error fetching library stories:', storyError.message);
169→        throw { status: 500, error: 'failed to fetch library stories' };
170→    }
171→
172→    if (!stories || stories.length === 0) {
173→        return { data: [], hasMore };
174→    }
175→
176→    // Batch-fetch author profiles
177→    const authorIds = [...new Set(stories.map(s => s.author_id))];
178→    const { data: authors } = await supabase
179→        .from('users')
180→        .select('id, name, image_url, username, badge')
181→        .in('id', authorIds);
182→
183→    const authorMap = {};
184→    (authors || []).forEach(a => { authorMap[a.id] = a; });
185→
186→    // Build story map for ordering
187→    const storyMap = {};
188→    stories.forEach(s => {
189→        const { embedding, ...rest } = s;
190→        storyMap[s.id] = { ...rest, users: authorMap[s.author_id] || null, in_library: true, added_at: addedAtMap[s.id] };
191→    });
192→
193→    // Return in library order (most recently added first)
194→    const ordered = storyIds.map(id => storyMap[id]).filter(Boolean);
195→
196→    return { data: ordered, hasMore };
197→};
