  2→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
  3→import { $getSelection, $isRangeSelection, $createTextNode } from 'lexical';
  4→import { $createMentionNode } from '../MentionNode';
  5→import { searchFollowingUsers } from '../../../../../../API/Api';
